{"content":"1: package clients
2: 
3: import (
4: 	"context"
5: 	"errors"
6: 	"strconv"
7: 	"strings"
8: 	"time"
9: 
10: 	"go.opentelemetry.io/otel/trace"
11: 
12: 	claims "github.com/grafana/authlib/types"
13: 	"github.com/grafana/grafana/pkg/apimachinery/errutil"
14: 	"github.com/grafana/grafana/pkg/components/apikeygen"
15: 	"github.com/grafana/grafana/pkg/components/satokengen"
16: 	"github.com/grafana/grafana/pkg/infra/log"
17: 	"github.com/grafana/grafana/pkg/services/apikey"
18: 	"github.com/grafana/grafana/pkg/services/authn"
19: 	"github.com/grafana/grafana/pkg/services/login"
20: 	"github.com/grafana/grafana/pkg/util"
21: )
22: 
23: var (
24: 	errAPIKeyInvalid     = errutil.Unauthorized("api-key.invalid", errutil.WithPublicMessage("Invalid API key"))
25: 	errAPIKeyExpired     = errutil.Unauthorized("api-key.expired", errutil.WithPublicMessage("Expired API key"))
26: 	errAPIKeyRevoked     = errutil.Unauthorized("api-key.revoked", errutil.WithPublicMessage("Revoked API key"))
27: 	errAPIKeyOrgMismatch = errutil.Unauthorized("api-key.organization-mismatch", errutil.WithPublicMessage("API key does not belong to the requested organization"))
28: )
29: 
30: var (
31: 	_ authn.HookClient         = new(APIKey)
32: 	_ authn.ContextAwareClient = new(APIKey)
33: )
34: 
35: const (
36: 	metaKeyID           = "keyID"
37: 	metaKeySkipLastUsed = "keySkipLastUsed"
38: )
39: 
40: func ProvideAPIKey(apiKeyService apikey.Service, tracer trace.Tracer) *APIKey {
41: 	return &APIKey{
42: 		log:           log.New(authn.ClientAPIKey),
43: 		apiKeyService: apiKeyService,
44: 		tracer:        tracer,
45: 	}
46: }
47: 
48: type APIKey struct {
49: 	log           log.Logger
50: 	apiKeyService apikey.Service
51: 	tracer        trace.Tracer
52: }
53: 
54: func (s *APIKey) Name() string {
55: 	return authn.ClientAPIKey
56: }
57: 
58: func (s *APIKey) Authenticate(ctx context.Context, r *authn.Request) (*authn.Identity, error) {
59: 	ctx, span := s.tracer.Start(ctx, "authn.apikey.Authenticate")
60: 	defer span.End()
61: 	key, err := s.getAPIKey(ctx, getTokenFromRequest(r))
62: 	if err != nil {
63: 		if errors.Is(err, satokengen.ErrInvalidApiKey) {
64: 			return nil, errAPIKeyInvalid.Errorf("API key is invalid")
65: 		}
66: 		return nil, err
67: 	}
68: 
69: 	if r.OrgID == 0 {
70: 		r.OrgID = key.OrgID
71: 	}
72: 
73: 	if err := validateApiKey(r.OrgID, key); err != nil {
74: 		return nil, err
75: 	}
76: 
77: 	// Set keyID so we can use it in last used hook
78: 	r.SetMeta(metaKeyID, strconv.FormatInt(key.ID, 10))
79: 	if !shouldUpdateLastUsedAt(key) {
80: 		// Hack to just have some value, we will check this key in the hook
81: 		// and if its not an empty string we will not update last used.
82: 		r.SetMeta(metaKeySkipLastUsed, "true")
83: 	}
84: 
85: 	return newServiceAccountIdentity(key), nil
86: }
87: 
88: func (s *APIKey) IsEnabled() bool {
89: 	return true
90: }
91: 
92: func (s *APIKey) getAPIKey(ctx context.Context, token string) (*apikey.APIKey, error) {
93: 	ctx, span := s.tracer.Start(ctx, "authn.apikey.getAPIKey")
94: 	defer span.End()
95: 	fn := s.getFromToken
96: 	if !strings.HasPrefix(token, satokengen.GrafanaPrefix) {
97: 		fn = s.getFromTokenLegacy
98: 	}
99: 
100: 	apiKey, err := fn(ctx, token)
101: 	if err != nil {
102: 		return nil, err
103: 	}
104: 
105: 	return apiKey, nil
106: }
107: 
108: func (s *APIKey) getFromToken(ctx context.Context, token string) (*apikey.APIKey, error) {
109: 	ctx, span := s.tracer.Start(ctx, "authn.apikey.getFromToken")
110: 	defer span.End()
111: 	decoded, err := satokengen.Decode(token)
112: 	if err != nil {
113: 		return nil, err
114: 	}
115: 
116: 	hash, err := decoded.Hash()
117: 	if err != nil {
118: 		return nil, err
119: 	}
120: 
121: 	return s.apiKeyService.GetAPIKeyByHash(ctx, hash)
122: }
123: 
124: func (s *APIKey) getFromTokenLegacy(ctx context.Context, token string) (*apikey.APIKey, error) {
125: 	ctx, span := s.tracer.Start(ctx, "authn.apikey.getFromTokenLegacy")
126: 	defer span.End()
127: 	decoded, err := apikeygen.Decode(token)
128: 	if err != nil {
129: 		return nil, err
130: 	}
131: 	// fetch key
132: 	keyQuery := apikey.GetByNameQuery{KeyName: decoded.Name, OrgID: decoded.OrgId}
133: 	key, err := s.apiKeyService.GetApiKeyByName(ctx, &keyQuery)
134: 	if err != nil {
135: 		return nil, err
136: 	}
137: 
138: 	// validate api key
139: 	isValid, err := apikeygen.IsValid(decoded, key.Key)
140: 	if err != nil {
141: 		return nil, err
142: 	}
143: 	if !isValid {
144: 		return nil, satokengen.ErrInvalidApiKey
145: 	}
146: 
147: 	return key, nil
148: }
149: 
150: func (s *APIKey) Test(ctx context.Context, r *authn.Request) bool {
151: 	return looksLikeApiKey(getTokenFromRequest(r))
152: }
153: 
154: func (s *APIKey) Priority() uint {
155: 	return 30
156: }
157: 
158: func (s *APIKey) Hook(ctx context.Context, identity *authn.Identity, r *authn.Request) error {
159: 	ctx, span := s.tracer.Start(ctx, "authn.apikey.Hook") //nolint:ineffassign,staticcheck
160: 	defer span.End()
161: 
162: 	if r.GetMeta(metaKeySkipLastUsed) != "" {
163: 		return nil
164: 	}
165: 
166: 	go func(keyID string) {
167: 		defer func() {
168: 			if err := recover(); err != nil {
169: 				s.log.Error("Panic during user last seen sync", "err", err)
170: 			}
171: 		}()
172: 
173: 		id, err := strconv.ParseInt(keyID, 10, 64)
174: 		if err != nil {
175: 			s.log.Warn("Invalid api key id", "id", keyID, "err", err)
176: 			return
177: 		}
178: 
179: 		if err := s.apiKeyService.UpdateAPIKeyLastUsedDate(context.Background(), id); err != nil {
180: 			s.log.Warn("Failed to update last used date for api key", "id", keyID, "err", err)
181: 			return
182: 		}
183: 	}(r.GetMeta(metaKeyID))
184: 
185: 	return nil
186: }
187: 
188: func looksLikeApiKey(token string) bool {
189: 	return token != ""
190: }
191: 
192: func getTokenFromRequest(r *authn.Request) string {
193: 	// api keys are only supported through http requests
194: 	if r.HTTPRequest == nil {
195: 		return ""
196: 	}
197: 
198: 	header := r.HTTPRequest.Header.Get("Authorization")
199: 
200: 	if strings.HasPrefix(header, bearerPrefix) {
201: 		return strings.TrimPrefix(header, bearerPrefix)
202: 	}
203: 	if strings.HasPrefix(header, basicPrefix) {
204: 		username, password, err := util.DecodeBasicAuthHeader(header)
205: 		if err == nil && username == "api_key" {
206: 			return password
207: 		}
208: 	}
209: 	return ""
210: }
211: 
212: func validateApiKey(orgID int64, key *apikey.APIKey) error {
213: 	if key.Expires != nil && *key.Expires <= time.Now().Unix() {
214: 		return errAPIKeyExpired.Errorf("API key has expired")
215: 	}
216: 
217: 	if key.IsRevoked != nil && *key.IsRevoked {
218: 		return errAPIKeyRevoked.Errorf("Api key is revoked")
219: 	}
220: 
221: 	if orgID != key.OrgID {
222: 		return errAPIKeyOrgMismatch.Errorf("API does not belong in Organization")
223: 	}
224: 
225: 	// plain API keys are no longer supported so an error is returned if the api key doesn't belong to a service account
226: 	if key.ServiceAccountId == nil || *key.ServiceAccountId < 1 {
227: 		return errAPIKeyInvalid.Errorf("API key does not belong to a service account")
228: 	}
229: 
230: 	return nil
231: }
232: 
233: func newServiceAccountIdentity(key *apikey.APIKey) *authn.Identity {
234: 	return &authn.Identity{
235: 		ID:              strconv.FormatInt(*key.ServiceAccountId, 10),
236: 		Type:            claims.TypeServiceAccount,
237: 		OrgID:           key.OrgID,
