106: func getRedirectToQueryParam(c *contextmodel.ReqContext) string {
107: 	redirectTo := c.Req.RequestURI
108: 	if setting.AppSubUrl != "" && strings.HasPrefix(redirectTo, setting.AppSubUrl) {
109: 		redirectTo = strings.TrimPrefix(redirectTo, setting.AppSubUrl)
110: 	}
111: 
112: 	if redirectTo == "/" {
113: 		return ""
114: 	}
115: 
116: 	// remove any forceLogin=true params
117: 	redirectTo = RemoveForceLoginParams(redirectTo)
118: 	return "?redirectTo=" + url.QueryEscape(redirectTo)
119: }
