3: import (
4: 	"context"
5: 	"strings"
6: 
7: 	"google.golang.org/grpc/codes"
8: 	"google.golang.org/grpc/metadata"
9: 	"google.golang.org/grpc/status"
10: 
11: 	"github.com/grafana/grafana/pkg/components/satokengen"
12: 	"github.com/grafana/grafana/pkg/infra/log"
13: 	"github.com/grafana/grafana/pkg/services/accesscontrol"
14: 	"github.com/grafana/grafana/pkg/services/apikey"
15: 	grpccontext "github.com/grafana/grafana/pkg/services/grpcserver/context"
16: 	"github.com/grafana/grafana/pkg/services/org"
17: 	"github.com/grafana/grafana/pkg/services/user"
18: )
19: 
20: type Authenticator interface {
21: 	Authenticate(ctx context.Context) (context.Context, error)
22: }
23: 
24: type AuthenticatorFunc func(context.Context) (context.Context, error)
25: 
26: func (fn AuthenticatorFunc) Authenticate(ctx context.Context) (context.Context, error) {
27: 	return fn(ctx)
28: }
29: 
30: // authenticator can authenticate GRPC requests.
31: type authenticator struct {
32: 	contextHandler grpccontext.ContextHandler
33: 	logger         log.Logger
34: 
35: 	APIKeyService        apikey.Service
36: 	UserService          user.Service
37: 	AccessControlService accesscontrol.Service
38: }
39: 
40: func ProvideAuthenticator(apiKeyService apikey.Service, userService user.Service, accessControlService accesscontrol.Service, contextHandler grpccontext.ContextHandler) Authenticator {
41: 	return &authenticator{
42: 		contextHandler: contextHandler,
43: 		logger:         log.New("grpc-server-authenticator"),
44: 
45: 		AccessControlService: accessControlService,
46: 		APIKeyService:        apiKeyService,
47: 		UserService:          userService,
48: 	}
49: }
50: 
51: // Authenticate checks that a token exists and is valid, and then removes the token from the
52: // authorization header in the context.
53: func (a *authenticator) Authenticate(ctx context.Context) (context.Context, error) {
54: 	return a.tokenAuth(ctx)
55: }
56: 
57: const tokenPrefix = "Bearer "
58: 
59: func (a *authenticator) tokenAuth(ctx context.Context) (context.Context, error) {
60: 	auth, err := extractAuthorization(ctx)
61: 	if err != nil {
62: 		return ctx, err
63: 	}
64: 
65: 	if !strings.HasPrefix(auth, tokenPrefix) {
66: 		return ctx, status.Error(codes.Unauthenticated, `missing "Bearer " prefix in "authorization" value`)
67: 	}
68: 
69: 	token := strings.TrimPrefix(auth, tokenPrefix)
70: 	if token == "" {
71: 		return ctx, status.Error(codes.Unauthenticated, "token required")
72: 	}
73: 
74: 	newCtx := purgeHeader(ctx, "authorization")
75: 
76: 	signedInUser, err := a.getSignedInUser(ctx, token)
77: 	if err != nil {
78: 		a.logger.Warn("request with invalid token", "error", err, "token", token)
79: 		return ctx, status.Error(codes.Unauthenticated, "invalid token")
80: 	}
81: 
82: 	newCtx = a.contextHandler.SetUser(newCtx, signedInUser)
83: 
84: 	return newCtx, nil
85: }
86: 
87: func (a *authenticator) getSignedInUser(ctx context.Context, token string) (*user.SignedInUser, error) {
88: 	decoded, err := satokengen.Decode(token)
89: 	if err != nil {
90: 		return nil, err
91: 	}
92: 
93: 	hash, err := decoded.Hash()
94: 	if err != nil {
95: 		return nil, err
96: 	}
97: 
98: 	apikey, err := a.APIKeyService.GetAPIKeyByHash(ctx, hash)
99: 	if err != nil {
100: 		return nil, err
101: 	}
102: 
103: 	if apikey == nil || apikey.ServiceAccountId == nil {
104: 		return nil, status.Error(codes.Unauthenticated, "api key does not have a service account")
105: 	}
106: 
107: 	querySignedInUser := user.GetSignedInUserQuery{UserID: *apikey.ServiceAccountId, OrgID: apikey.OrgID}
108: 	signedInUser, err := a.UserService.GetSignedInUser(ctx, &querySignedInUser)
109: 	if err != nil {
110: 		return nil, err
111: 	}
112: 
113: 	if signedInUser == nil {
114: 		return nil, status.Error(codes.Unauthenticated, "service account not found")
115: 	}
116: 
117: 	if !signedInUser.HasRole(org.RoleAdmin) {
118: 		return nil, status.Error(codes.PermissionDenied, "service account does not have admin role")
119: 	}
120: 
121: 	// disabled service accounts are not allowed to access the API
122: 	if signedInUser.IsDisabled {
123: 		return nil, status.Error(codes.PermissionDenied, "service account is disabled")
124: 	}
125: 
126: 	if signedInUser.Permissions == nil {
127: 		signedInUser.Permissions = make(map[int64]map[string][]string)
128: 	}
129: 
130: 	if signedInUser.Permissions[signedInUser.OrgID] == nil {
131: 		permissions, err := a.AccessControlService.GetUserPermissions(ctx, signedInUser, accesscontrol.Options{})
132: 		if err != nil {
133: 			a.logger.Error("failed fetching permissions for user", "userID", signedInUser.UserID, "error", err)
134: 		}
135: 		signedInUser.Permissions[signedInUser.OrgID] = accesscontrol.GroupScopesByActionContext(context.Background(), permissions)
136: 	}
137: 
138: 	return signedInUser, nil
139: }
140: 
141: func extractAuthorization(ctx context.Context) (string, error) {
142: 	md, ok := metadata.FromIncomingContext(ctx)
143: 	if !ok {
144: 		return "", status.Error(codes.Unauthenticated, "no headers in request")
145: 	}
146: 
147: 	authHeaders, ok := md["authorization"]
148: 	if !ok {
149: 		return "", status.Error(codes.Unauthenticated, `no "authorization" header in request`)
150: 	}
151: 
152: 	if len(authHeaders) != 1 {
153: 		return "", status.Error(codes.Unauthenticated, `malformed "authorization" header: one value required`)
154: 	}
155: 
156: 	return authHeaders[0], nil
157: }
158: 
159: func purgeHeader(ctx context.Context, header string) context.Context {
160: 	md, _ := metadata.FromIncomingContext(ctx)
161: 	mdCopy := md.Copy()
162: 	mdCopy[header] = nil
163: 	return metadata.NewIncomingContext(ctx, mdCopy)
164: }
